function deriveComboFromSubjects(selectedIds){
  const has = id => selectedIds.includes(id);
  const hasMaths    = has('maths') || has('further-maths') || has('statistics');
  const hasPhys     = has('physics');
  const hasChem     = has('chemistry');
  const hasBio      = has('biology');
  const hasCS       = has('cs') || has('ict');
  const hasCommerce = has('economics') || has('business') || has('accounting');
  const hasArts     = has('art') || has('photography') || has('music') || has('drama');
  const hasHum      = has('history') || has('geography') || has('psychology') ||
                      has('sociology') || has('pol-science');

  if (hasPhys && hasChem && hasMaths && hasBio) return 'PCMB';
  if (hasPhys && hasChem && hasMaths && hasCS)  return 'PCM+CS';
  if (hasPhys && hasChem && hasMaths)            return 'PCM';
  if (hasPhys && hasChem && hasBio)              return 'PCB';
  if (hasCommerce && hasMaths)                   return 'Commerce+Maths';
  if (hasCommerce)                               return 'Commerce';
  if (hasArts || hasHum)                         return 'Arts';
  if (selectedIds.length > 0)                    return 'Any';
  return null;
}
